func TestHandleProjectIDERejectsProjectsWithoutWorkspacePath(t *testing.T) {
	opener := &recordingIDEOpener{}
	server := New(Config{
		IDEOpener: opener,
		Workspace: session.Workspace{
			Projects: []session.Project{
				{
					ID:   "project-a",
					Name: "Project A",
				},
			},
		},
	})
